use askama::Template;
use axum::extract::{Path, State};
use axum::http::StatusCode;
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;
use uuid::Uuid;

use super::auth::AuthenticatedUser;
use crate::domain::{TodoItem, TodoItemId};
use crate::services::todo_service::{add_todo, get_todos, toggle_todo_completion, AddTodoError, ToggleTodoError};

/// View model for a single todo item in the template.
pub struct TodoItemView {
    #[allow(dead_code)] // Used in complete/delete actions (Task #8, #9)
    pub id: String,
    pub title: String,
    pub is_completed: bool,
}

impl From<&TodoItem> for TodoItemView {
    fn from(item: &TodoItem) -> Self {
        Self {
            id: item.id().as_uuid().to_string(),
            title: item.title().as_str().to_string(),
            is_completed: item.is_completed(),
        }
    }
}

#[derive(Template)]
#[template(path = "todos.html")]
pub struct TodosTemplate {
    pub todos: Vec<TodoItemView>,
    pub error_message: Option<String>,
}

pub async fn get_todos_page(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, TodosError> {
    let todos = get_todos(&pool, &user_id)
        .await
        .map_err(TodosError::Unexpected)?;

    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();

    let template = TodosTemplate {
        todos: todo_views,
        error_message: None,
    };
    Ok(Html(template.render()?))
}

#[derive(serde::Deserialize)]
pub struct AddTodoForm {
    pub title: String,
}

pub async fn post_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Form(form): Form<AddTodoForm>,
) -> Result<Response, TodosError> {
    // Silently ignore empty/whitespace-only submissions per US-5
    if form.title.trim().is_empty() {
        return Ok(Redirect::to("/todos").into_response());
    }

    match add_todo(&pool, user_id.clone(), form.title).await {
        Ok(_) => Ok(Redirect::to("/todos").into_response()),
        Err(AddTodoError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                crate::domain::TodoTitleError::Empty => {
                    // Should not reach here due to empty check above, but handle gracefully
                    return Ok(Redirect::to("/todos").into_response());
                }
                crate::domain::TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };

            let todos = get_todos(&pool, &user_id)
                .await
                .map_err(TodosError::Unexpected)?;
            let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();

            let template = TodosTemplate {
                todos: todo_views,
                error_message: Some(user_facing),
            };
            let body = template.render().map_err(TodosError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(AddTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

#[derive(Debug, thiserror::Error)]
pub enum TodosError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for TodosError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Todos error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{TodoItem, TodoItemId, TodoTitle, UserId};

pub struct TodoRecord {
    pub id: Uuid,
    pub user_id: Uuid,
    pub title: String,
    pub completed_at: Option<DateTime<Utc>>,
    pub created_at: DateTime<Utc>,
}

impl TodoRecord {
    pub fn to_domain(self) -> TodoItem {
        let id = TodoItemId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        // Title was validated on insert, so we trust it here
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        match self.completed_at {
            Some(completed_at) => TodoItem::Completed {
                id,
                user_id,
                title,
                created_at: self.created_at,
                completed_at,
            },
            None => TodoItem::Pending {
                id,
                user_id,
                title,
                created_at: self.created_at,
            },
        }
    }
}

pub async fn insert_todo(pool: &PgPool, item: &TodoItem) -> Result<(), sqlx::Error> {
    let (completed_at, created_at) = match item {
        TodoItem::Pending { created_at, .. } => (None, *created_at),
        TodoItem::Completed {
            created_at,
            completed_at,
            ..
        } => (Some(*completed_at), *created_at),
    };

    sqlx::query!(
        r#"INSERT INTO todos (id, user_id, title, completed_at, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz, $5 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        completed_at as Option<DateTime<Utc>>,
        created_at as DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_todos_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<TodoItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        TodoRecord,
        r#"SELECT id, user_id, title,
           completed_at as "completed_at: DateTime<Utc>",
           created_at as "created_at: DateTime<Utc>"
           FROM todos WHERE user_id = $1 ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.to_domain()).collect())
}

pub async fn find_todo_by_id(
    pool: &PgPool,
    todo_id: &TodoItemId,
) -> Result<Option<TodoItem>, sqlx::Error> {
    let record = sqlx::query_as!(
        TodoRecord,
        r#"SELECT id, user_id, title,
           completed_at as "completed_at: DateTime<Utc>",
           created_at as "created_at: DateTime<Utc>"
           FROM todos WHERE id = $1"#,
        todo_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r| r.to_domain()))
}

pub async fn update_todo_completion(
    pool: &PgPool,
    todo_id: &TodoItemId,
    completed_at: Option<DateTime<Utc>>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE todos SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as Option<DateTime<Utc>>,
        todo_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

