use axum::Router;
use sqlx::postgres::PgPoolOptions;
use sqlx::PgPool;
use tokio::net::TcpListener;
use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
use tower_http::services::ServeDir;
use tower_http::trace::TraceLayer;
use tower_sessions::SessionManagerLayer;
use tower_sessions_sqlx_store::PostgresStore;

use crate::configuration::Settings;
use crate::routes::{
    get_login, get_register, get_todos_page, health_check, index, post_delete_todo, post_login,
    post_logout, post_register, post_todo, post_toggle_todo,
};

pub struct Application {
    listener: TcpListener,
    pool: PgPool,
}

impl Application {
    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
        let pool = PgPoolOptions::new()
            .max_connections(5)
            .connect_with(settings.database.connect_options())
            .await?;

        sqlx::migrate!("./migrations").run(&pool).await?;

        let session_store = PostgresStore::new(pool.clone());
        session_store.migrate().await?;

        let address = format!(
            "{}:{}",
            settings.application.host, settings.application.port
        );
        let listener = TcpListener::bind(&address).await?;

        tracing::info!("Listening on {}", listener.local_addr()?);

        Ok(Self { listener, pool })
    }

    pub fn port(&self) -> u16 {
        self.listener.local_addr().unwrap().port()
    }

    pub fn router(pool: PgPool) -> Router {
        let x_request_id = axum::http::HeaderName::from_static("x-request-id");

        let session_store = PostgresStore::new(pool.clone());
        let session_layer = SessionManagerLayer::new(session_store);

        Router::new()
            .route("/", axum::routing::get(index))
            .route(
                "/register",
                axum::routing::get(get_register).post(post_register),
            )
            .route("/login", axum::routing::get(get_login).post(post_login))
            .route("/logout", axum::routing::post(post_logout))
            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
            .route("/health_check", axum::routing::get(health_check))
            .nest_service("/static", ServeDir::new("static"))
            .layer(session_layer)
            .layer(TraceLayer::new_for_http())
            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
            .with_state(pool)
    }

    pub async fn run(self) -> Result<(), std::io::Error> {
        let router = Self::router(self.pool);
        axum::serve(self.listener, router).await
    }
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{TodoItem, TodoItemId, TodoTitle, UserId};

pub struct TodoRecord {
    pub id: Uuid,
    pub user_id: Uuid,
    pub title: String,
    pub completed_at: Option<DateTime<Utc>>,
    pub created_at: DateTime<Utc>,
}

impl TodoRecord {
    pub fn to_domain(self) -> TodoItem {
        let id = TodoItemId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        // Title was validated on insert, so we trust it here
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        match self.completed_at {
            Some(completed_at) => TodoItem::Completed {
                id,
                user_id,
                title,
                created_at: self.created_at,
                completed_at,
            },
            None => TodoItem::Pending {
                id,
                user_id,
                title,
                created_at: self.created_at,
            },
        }
    }
}

pub async fn insert_todo(pool: &PgPool, item: &TodoItem) -> Result<(), sqlx::Error> {
    let (completed_at, created_at) = match item {
        TodoItem::Pending { created_at, .. } => (None, *created_at),
        TodoItem::Completed {
            created_at,
            completed_at,
            ..
        } => (Some(*completed_at), *created_at),
    };

    sqlx::query!(
        r#"INSERT INTO todos (id, user_id, title, completed_at, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz, $5 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        completed_at as Option<DateTime<Utc>>,
        created_at as DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_todos_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<TodoItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        TodoRecord,
        r#"SELECT id, user_id, title,
           completed_at as "completed_at: DateTime<Utc>",
           created_at as "created_at: DateTime<Utc>"
           FROM todos WHERE user_id = $1 ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.to_domain()).collect())
}

pub async fn find_todo_by_id(
    pool: &PgPool,
    todo_id: &TodoItemId,
) -> Result<Option<TodoItem>, sqlx::Error> {
    let record = sqlx::query_as!(
        TodoRecord,
        r#"SELECT id, user_id, title,
           completed_at as "completed_at: DateTime<Utc>",
           created_at as "created_at: DateTime<Utc>"
           FROM todos WHERE id = $1"#,
        todo_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r| r.to_domain()))
}

pub async fn delete_todo(pool: &PgPool, todo_id: &TodoItemId) -> Result<(), sqlx::Error> {
    sqlx::query!(r#"DELETE FROM todos WHERE id = $1"#, todo_id.as_uuid(),)
        .execute(pool)
        .await?;
    Ok(())
}

pub async fn update_todo_completion(
    pool: &PgPool,
    todo_id: &TodoItemId,
    completed_at: Option<DateTime<Utc>>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE todos SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as Option<DateTime<Utc>>,
        todo_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

