... 147 #[derive(Template)]
... 148 #[template(path = "edit_todo.html")]
... 149 pub struct EditTodoTemplate {
... 150     pub todo_id: String,
... 151     pub current_title: String,
... 152     pub error_message: Option<String>,
... 153 }
... 154 
... 155 pub async fn get_edit_todo(
... 156     AuthenticatedUser(user_id): AuthenticatedUser,
... 157     State(pool): State<PgPool>,
... 158     Path(todo_id): Path<Uuid>,
... 159 ) -> Result<Response, TodosError> {
... 160     let todo_item_id = TodoItemId::from_uuid(todo_id);
... 161 
... 162     let item = crate::infrastructure::todo_repository::find_todo_by_id(&pool, &todo_item_id)
... 163         .await
... 164         .map_err(|e| TodosError::Unexpected(anyhow::anyhow!("Database error: {e}")))?;
... 165 
... 166     match item {
... 167         Some(todo) if todo.user_id() == &user_id => {
... 168             let template = EditTodoTemplate {
... 169                 todo_id: todo_id.to_string(),
... 170                 current_title: todo.title().as_str().to_string(),
... 171                 error_message: None,
... 172             };
... 173             Ok(Html(template.render()?).into_response())
... 174         }
... 175         Some(_) => Ok((
... 176             StatusCode::FORBIDDEN,
... 177             Html("<h1>Not authorized</h1>".to_string()),
... 178         )
... 179             .into_response()),
... 180         None => Ok((
... 181             StatusCode::NOT_FOUND,
... 182             Html("<h1>Todo not found</h1>".to_string()),
... 183         )
... 184             .into_response()),
... 185     }
... 186 }
