... 188 #[derive(serde::Deserialize)]
... 189 pub struct EditTodoForm {
... 190     pub title: String,
... 191 }
... 192 
... 193 pub async fn post_edit_todo(
... 194     AuthenticatedUser(user_id): AuthenticatedUser,
... 195     State(pool): State<PgPool>,
... 196     Path(todo_id): Path<Uuid>,
... 197     Form(form): Form<EditTodoForm>,
... 198 ) -> Result<Response, TodosError> {
... 199     let todo_item_id = TodoItemId::from_uuid(todo_id);
... 200 
... 201     match update_todo_title(&pool, &todo_item_id, &user_id, form.title.clone()).await {
... 202         Ok(()) => Ok(Redirect::to("/todos").into_response()),
... 203         Err(UpdateTitleError::NotFound) => Ok((
... 204             StatusCode::NOT_FOUND,
... 205             Html("<h1>Todo not found</h1>".to_string()),
... 206         )
... 207             .into_response()),
... 208         Err(UpdateTitleError::Unauthorized) => Ok((
... 209             StatusCode::FORBIDDEN,
... 210             Html("<h1>Not authorized</h1>".to_string()),
... 211         )
... 212             .into_response()),
... 213         Err(UpdateTitleError::InvalidTitle(title_err)) => {
... 214             let user_facing = match title_err {
... 215                 crate::domain::TodoTitleError::Empty => "Title cannot be empty".to_string(),
... 216                 crate::domain::TodoTitleError::TooLong { max, .. } => {
... 217                     format!("That title is too long (max {max} characters)")
... 218                 }
... 219             };
... 220             let template = EditTodoTemplate {
... 221                 todo_id: todo_id.to_string(),
... 222                 current_title: form.title,
... 223                 error_message: Some(user_facing),
... 224             };
... 225             let body = template.render().map_err(TodosError::Render)?;
... 226             Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
... 227         }
... 228         Err(UpdateTitleError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
... 229     }
... 230 }
